    const tabu = initTabu(
        row,
        col,
    ); /* Time O(ROWS * COLS) | Space O(ROWS * COLS) */

    search(row, col, tabu); /* Time O(ROWS * COLS) | Space O(ROWS * COLS) */

    return tabu[row - 1][col - 1];
};

