    for (let _row = 1; _row < row; _row++) {
        /* Time O(ROWS)*/
        for (let _col = 1; _col < col; _col++) {
            /* Time O(COLS)*/
            const left = tabu[_row - 1][_col];
            const right = tabu[_row][_col - 1];

            tabu[_row][_col] = left + right; /* Space O(ROWS * COLS) */
        }
    }
};

