    for (let _row = 0; _row < row; _row++) {
        /* Time O(ROWS) */
        tabu[_row][0] = 1; /*              | Space O(ROWS * COLS) */
    }

    for (let _col = 0; _col < col; _col++) {
        /* Time O(COLS) */
